@tool
def execute_sql(query: str) -> str:
    """Execute a guarded SQL query."""
    return f"[SQL] Result for {query[:50]}..."

@tool
def run_cypher(query: str) -> str:
    """Execute a Cypher query."""
    return f"[Cypher] Result for {query[:50]}..."

@tool
def query_knowledge_graph(question: str) -> str:
    """Answer using the knowledge graph."""
    return f"[KG] Answer for {question}"

@tool
def search_glossary(term: str) -> str:
    """Search glossary."""
    return f"[Glossary] Definition of {term}"

@tool
def query_ontology(sparql: str) -> str:
    """Execute SPARQL query."""
    return f"[SPARQL] Result for {sparql[:50]}..."

@tool
def expand_ontology(class_uri: str) -> str:
    """Get subclasses/superclasses."""
    return f"[Ontology] Subclasses of {class_uri}: [Asset, Equity]"

@tool
def reason_about_class(class_uri: str) -> str:
    """HermiT reasoning."""
    return f"[Reasoner] {class_uri} is consistent."

@tool
def page_rank(label: str) -> str:
    """PageRank on given label."""
    return f"[GDS] PageRank for {label}: top nodes..."

@tool
def find_communities(label: str) -> str:
    """Community detection."""
    return f"[GDS] Communities for {label}: 3 found."

@tool
def graph_rag_query(question: str) -> str:
    """GraphRAG hybrid search."""
    return f"[GraphRAG] Answer for {question}"

@tool
def ingest_document(text: str) -> str:
    """Ingest document."""
    return "[Docs] Ingested: 5 mentions, 2 resolved."

@tool
def resolve_mentions(doc_id: str) -> str:
    """Resolve mentions."""
    return f"[Docs] Resolved mentions for {doc_id}"

state = supervisor_app.get_state(config)
for msg in state.values["messages"]:
    if hasattr(msg, "content") and msg.content:
        print(f"[{msg.type.upper()}]: {msg.content[:200]}")
